async function magicVerify(request, env) {
  const url = new URL(request.url);
  const token = url.searchParams.get("token");
  if (!token) return Response.redirect("https://ricardoruiz.co/login.html?error=invalid", 302);
  const raw = await env.RR_STORE.get(`magic:${token}`);
  if (!raw) return Response.redirect("https://ricardoruiz.co/login.html?error=expired", 302);
  const { email, isNewUser } = JSON.parse(raw);
  await env.RR_STORE.delete(`magic:${token}`);
  if (isNewUser) {
    const setupToken = randomToken();
    await env.RR_STORE.put(`magic-setup:${setupToken}`, JSON.stringify({ email, createdAt: Date.now() }), { expirationTtl: 60 * 30 });
    return Response.redirect(`https://ricardoruiz.co/magic-verify.html?setup=${setupToken}`, 302);
  }
  const userRaw = await env.RR_STORE.get(`users:${email}`);
  if (!userRaw) return Response.redirect("https://ricardoruiz.co/login.html?error=notfound", 302);
  const user = JSON.parse(userRaw);
  const sessionToken = randomToken();
  await env.RR_STORE.put(`sessions:${sessionToken}`, JSON.stringify({ email: user.email, name: user.name, plan: user.plan, createdAt: Date.now() }), { expirationTtl: 60 * 60 * 24 * 30 });
  return Response.redirect(`https://ricardoruiz.co/magic-verify.html?token=${sessionToken}&name=${encodeURIComponent(user.name)}&plan=${user.plan}`, 302);
}

async function magicComplete(request, env) {
  let body;
  try { body = await request.json(); } catch { return err("JSON inválido"); }
  const { setupToken, name, country } = body;
  if (!setupToken || !name || !country) return err("Faltan campos");
  const raw = await env.RR_STORE.get(`magic-setup:${setupToken}`);
  if (!raw) return err("Enlace expirado", 400);
  const { email } = JSON.parse(raw);
  const existing = await env.RR_STORE.get(`users:${email}`);
  if (existing) return err("Ya existe una cuenta con ese correo", 409);
  const user = { name: name.trim(), email, country, salt: null, hash: null, plan: "free", createdAt: Date.now(), verified: true, authMethod: "magic" };
  await env.RR_STORE.put(`users:${email}`, JSON.stringify(user));
  await env.RR_STORE.delete(`magic-setup:${setupToken}`);
  const sessionToken = randomToken();
  await env.RR_STORE.put(`sessions:${sessionToken}`, JSON.stringify({ email: user.email, name: user.name, plan: user.plan, createdAt: Date.now() }), { expirationTtl: 60 * 60 * 24 * 30 });
  return ok({ message: "Cuenta creada", token: sessionToken, user: { name: user.name, email: user.email, plan: user.plan } });
}
